@ARTICLE{ris_000001,
	author = {车欣 and 柴淑君 and 赵丹 and 周成超},
	title = {消费水平在老年慢性病患者互联网使用与门诊服务利用间的中介作用分析},
	journal = {中国卫生事业管理},
	year = {2026},
	keywords = {门诊服务利用; 互联网使用; 慢病老年患者; 消费水平 ER -},
	abstract = {目的:分析老年慢性病患者互联网使用与门诊服务利用关系,并探讨消费水平的中介作用,为优化老年慢性病患者健康管理策略提供参考。方法:数据来源于中国健康与养老追踪调查2018年数据,共有7151名60岁及以上老年慢性病患者被纳入分析。采用Logistic回归模型分析互联网使用与门诊服务利用之间的关系,并采用KHB方法检验消费水平在其中的中介效应。结果:老年慢性病患者的互联网使用率和门诊服务利用率分别为6.52%和17.83%。调整混杂因素后,互联网使用与门诊服务利用呈显著正相关[OR=1.321,95%CI:(1.028,1.697)]。消费水平可中介互联网使用与老年慢性病患者门诊服务利用的关系[OR=1.063,95%CI:(1.033~1.094)],中介效应占总效应的比例为18.04%。结论:互联网使用行为和老年慢性病患者门诊服务利用相关,消费水平在两者的关系中起中介作用。政府应采取措施加强数字基础设施,优化互联网信息环境,开发老年友好型数字健康工具,引导慢病老年人消费向慢病监测、随访和预防倾斜,促进慢性病管理与数字化应用的有效融合。},
	type = {JOUR}
}

@ARTICLE{ris_000002,
	author = {金孔军 and 陈三妹 and 孙一勤 and 徐水琴},
	title = {辅助机器人应用于失能老人社区康复的研究进展},
	journal = {军事护理},
	year = {2026},
	keywords = {机器人; 失能老人; 社区 ER -},
	abstract = {<正>随着全球老龄化发展加速,老年群体失能问题逐渐突出[1]。有研究[2]预测,2050年全球60岁以上人口占比将超过22%,其中患有慢性疾病、认知障碍或行动能力受限的失能老人比例将显著增加。多数失能老人由家庭成员照顾,家庭成员在经济、时间和情感上承受着巨大压力。在全球信息化背景下,辅助机器人技术日益成熟,极大地改变着人们的生活方式。为了加快推进机器人应用拓展,2023年2月国家工业和信息化部、教育部等17个部门联合印发了《“机器人+”应用行动实施方案》[3],该方案明确提出了加快研制残障辅助、康复训练、情感陪护、安防监控等助老助残机器人产品,研发科技助老新技术的要求。辅助机器人技术作为人工智能与医疗健康融合的前沿领域产品,为失能老人照护资源短缺难题提供创新性解决方案。本研究通过论述辅助类机器人在失能老年群体社区康复中的应用情况,叙述其应用优势与挑战,为其进一步推广实践提供参考。},
	type = {JOUR}
}

@ARTICLE{ris_000003,
	author = {贾洪磊},
	title = {基于多模态人工智能的老年人睡眠障碍监测与干预系统理论框架研究},
	journal = {医用生物力学},
	year = {2026},
	abstract = {目的 通过智能可穿戴设备实时采集心率变异性、呼吸节律、体位转换频率等关键指标,并同步监测皮肤温度与血压波动参数。结合监督式机器学习框架与深度强化学习算法,建立基于生理信号特征提取的睡眠阶段识别模型,构建个性化运动干预方案生成机制,为睡眠障碍老年群体设计具有循证依据的睡眠优化策略。方法 1)数据采集与整合:智能可穿戴设备(如智能戒指)对老年慢性病群体进行持续动态监测,同步采集包括心电信号、呼吸波形、体动频率、体表温度及动态血压在内的多维生理参数,并通过嵌入式系统实现数据的实时传输与分析。依托数据整合方法,把所收集到的、来源各异的数据统一汇聚至同一个数据库之中。在此基础上,开展数据预处理,比如进行数据清洗、转换等操作,同时实施严格的数据质量控制。2)睡眠分期与结构解析:依托梯度提升决策树模型,对经过预处理的多模态生理数据展开分析工作。在此过程中,借助该模型的数据分析能力,确定老年人的睡眠时相,具体涵盖觉醒状态、慢波睡眠(NREM)以及快波睡眠(REM)这几种状态,同时明确其睡眠结构情况。3)个性化运动处方生成:依托Deep Seek-R1模型的触发机制,综合考量老年人具体的睡眠状况,以及其个人在运动方面的偏好。在此基础上,生成一份具有针对性的个性化运动处方。该处方涵盖了运动类型、运动频率、运动强度、运动时间、运动总量、运动进度、注意事项。4)动态干预与优化策略:依托用户阶段性睡眠质量反馈,Q-Learning模型可对训练计划予以动态调整。该过程中,模型依据实时反馈信息,有针对性地优化训练参数。结果 1)精准睡眠评估与个性化干预:该系统达成对老年人睡眠状态的精准评估。基于这一精准评估结果,进而生成了契合老年人个体特征的个性化运动处方。此运动处方充分考虑了老年人的身体状况、睡眠质量等多方面因素,具有较强的针对性和适用性。2)动态调整与持续优化:Q-Learning模型根据用户反馈动态调整训练计划,确保了个性化运动处方的持续有效性。依托时间序列分析模型(LSTM模型),其成功达成了对用户长期睡眠健康趋势的预测工作。3)系统可靠性与用户体验:系统在多模态生理数据采集、处理与分析方面表现出色,具有较高的可靠性和稳定性。老年人用户对系统的使用体验良好,认为系统操作简便、易于理解且效果显著。结论 该系统达成对老年人睡眠状态的精准评估,同时能开展个性化干预。系统可动态调整训练计划,还能预测老年人长期睡眠健康趋势,由此,老年人的睡眠质量得以有效提高。此系统还具备较高的可靠性与稳定性。未来,进一步聚焦于优化算法模型,同时完善多模型协同机制。通过这些举措,期望能够更好地提升睡眠健康服务的质量与效率,为老年人的睡眠健康提供更有力的保障。 ER -},
	type = {JOUR}
}

@ARTICLE{10.13723/j.yxysh.2025.11.016,
	author = {车欣 and 柴淑君 and 周成超 and 赵丹},
	title = {数字技术在老年慢性病领域应用的研究现状、热点和演进趋势},
	journal = {医学与社会},
	year = {2025},
	keywords = {卫生信息管理; 老年慢性病; 数字技术; 研究热点 ER -},
	abstract = {目的:梳理数字技术在老年慢性病领域应用的研究现状、热点和演进趋势,为促进数字技术在老年慢性病领域的有效应用提供参考。方法:以Web of Science核心合集数据库为数据来源,选取2003年1月-2023年12月发表的数字技术在老年慢性病领域应用的相关文献为分析对象,采用CiteSpace 6.2.R6软件对发文国家/地区进行共现分析,对关键词等进行共现、聚类和突现分析,并绘制Timezone时区图。结果:共纳入439篇文献,发文最多的国家是美国。出现频次排在前5位的关键词分别是数字健康、老年人、慢性病、照料、技术。关键词聚类分析显示,研究的热点聚焦在个人数字助理、患者参与、数字鸿沟等方面。Timezone时区图显示该领域的演进趋势大体上可分为初步探索、稳步发展、快速发展3个阶段。结论:国际上对数字技术与老年慢性病领域的研究热度呈持续上升趋势,研究领域已经从数字干预开始转向数字鸿沟、数字健康等领域,移动健康、数字表型等新兴名词不断出现,为我国应用数字技术对老年慢性病开展研究和进行干预提供了思路。},
	doi = {10.13723/j.yxysh.2025.11.016},
	type = {JOUR}
}

@ARTICLE{ris_000005,
	author = {南鹤 and 张锌 and 王旭},
	title = {“互联网+”慢性病健康管理系统对老年类风湿关节炎患者疾病活动度的影响},
	journal = {中国老年学杂志},
	year = {2025},
	keywords = {“互联网+”慢性病健康管理系统; 居家管理; 类风湿关节炎 ER -},
	abstract = {目的 探讨“互联网+”慢性病健康管理系统对老年类风湿关节炎(RA)患者疾病活动度的影响。方法 98例RA居家老年患者采用随机数字表法分为对照组和观察组各49例。对照组给予常规居家管理,观察组在此基础上联合“互联网+”慢性病健康管理系统,6个月后比较两组干预前后的疾病活动度、自我管理能力。结果 经过6个月的干预,观察组总体疾病严重度评分(GH)、关节肿胀数(SJC)、关节压痛数(TJC)、红细胞沉降率(ESR)、C-反应蛋白(CRP)、28个关节疾病活动度评分(DAS28)显著低于对照组(P<0.05);干预后,观察组自我管理评分及各维度评分均高于对照组,差异有统计学意义(P<0.05)。结论 “互联网+”慢性病健康管理系统理能帮助降低老年RA患者疾病的活动度,提高自我管理能力。},
	type = {JOUR}
}

@ARTICLE{ris_000006,
	author = {陈举凤 and 朱姝欣 and 赵孙安婕 and 陈昱希 and 陶佩亚 and 韩国虎 and 王濯},
	title = {生态瞬时干预在老年慢性病患者体力活动中应用的范围综述},
	journal = {中国护理管理},
	year = {2025},
	keywords = {老年人; 慢性病; 生态瞬时干预; 体力活动; 范围综述 ER -},
	abstract = {目的 :对生态瞬时干预(Ecological Momentary Intervention,EMI)在老年慢性病患者体力活动中应用的相关研究进行范围综述,为优化EMI在老年慢性病管理中的应用提供参考。方法 :按范围综述报告框架,检索中英文数据库中相关文献,检索时间为建库至2025年2月28日。结果 :纳入20篇文献,EMI干预载体多为应用程序和可穿戴设备,干预类别多为简单和交互EMI。瞬时评估内容为行为数据和情境变量;触发规则包含用户启动、固定时间、随机时间和决策规则;干预内容由静态和动态两部分组成,呈现方式包括视觉反馈、触觉反馈和激励信息等;干预结局包含近期结局和远期结局。EMI在癌症、糖尿病和冠心病患者中应用广泛,可行性和可接受性已得到初步证实,体力活动提升量为29~220 min/周、步数为297.7~1 920步/天、久坐时间减少21~262.2 min/天;干预参与度为33%~100%。结论 :EMI在老年慢性病患者体力活动应用中具有可行性和有效性,有助于提升体力活动、增加步数、减少久坐时间,但干预参与度有待进一步提升。},
	type = {JOUR}
}

@ARTICLE{ris_000007,
	author = {余新艳 and 杨建云 and 姜清茹 and 陈涛 and 苏鹏 and 王思洋 and 罗占武 and 张海澄},
	title = {基于单导联可穿戴心电设备的宁夏回族自治区基层老年高血压患者病程与自主神经损害的相关性研究},
	journal = {中国全科医学},
	year = {2025},
	keywords = {高血压; 老年人; 病程; 自主神经; 基层医疗卫生机构; 单导联可穿戴心电设备 ER -},
	abstract = {背景 高血压是我国基层医疗卫生机构管理的主要慢性病。心脏自主神经功能紊乱是引起血压调控失衡,发生不良心血管事件的主要原因。因此在基层医疗卫生机构借助高效便携的单导联可穿戴心电设备探索老年高血压患者与自主神经之间关系,可为基层高血压患者管理和心血管疾病防控提供简单、高效、低成本且可持续的适宜方法和客观依据。目的 基于单导联可穿戴心电设备探索宁夏回族自治区基层医疗卫生机构老年高血压患者病程与自主神经功能损害的相关性。方法 选取2021年12月—2022年12月宁夏回族自治区20家基层医疗卫生机构应用单导联可穿戴心电设备采集并上传至云平台的2 137例65岁以上高血压患者为研究对象,收集患者的72 h心电图资料及云平台收集的患者基本信息、心理健康及生活方式等资料。自主神经损害依据心率变异性(HRV)时域参数全部窦性心搏RR间期的标准差(SDNN)结果分为正常组(SDNN>100 ms)470例及异常组(SDNN≤100 ms)1 667例。通过1∶1比例行倾向评分匹配校正混杂因素,卡钳值为0.02,以逆概率处理加权法作为参考,验证倾向评分匹配的匹配效果,采用单因素和多因素Logistic回归分析探讨高血压病程与自主神经损伤之间的关系,同时进一步验证倾向评分匹配的效果,采用倾向性评分匹配,基于高血压病程和自主神经损伤,行匹配前和匹配后敏感性亚组分析,同时采用限制性三次样条(RCS)分析来检验高血压病程与自主神经损害是否存在非线性关联及反应效应。结果 共收集1级高血压479例,2级高血压1 658例;病程<5年者1 203例、5~<10年者753例、10~<15年者110例、15~<20年者41例、20~<30年者26例、≥30年者4例。多因素Logistic回归分析显示匹配前后高血压患者自主神经损害与病程呈正相关(P<0.001)。亚组分析显示,匹配前后80岁以下、较低的教育程度、无共病冠心病的高血压患者,以及女性、共病阻塞性呼吸睡眠暂停(OSA)的高血压患者病程与自主神经损害的相关性更大,差异有统计学意义(P<0.05),交互作用有统计学意义(P<0.05)。但RCS分析显示匹配前后高血压患者病程与自主神经损害无非线性关系。结论 宁夏回族自治区基层老年高血压患者病程与自主神经损害呈正相关。基层医疗卫生机构应加强对患者的健康宣教,提高患者治疗的依从性,可延缓高血压患者自主神经损害。},
	type = {JOUR}
}

@ARTICLE{10.13723/j.yxysh.2025.07.010,
	author = {吾丽盼·乌杰提 and 姚萱 and 李云龙 and 安伟华},
	title = {乌鲁木齐市老年慢性病患者“互联网+健康管理”服务使用意愿及其影响因素},
	journal = {医学与社会},
	year = {2025},
	keywords = {健康管理; 互联网+; 老年人; 慢性病患者; 使用意愿; 影响因素; 乌鲁木齐 ER -},
	abstract = {目的:探讨乌鲁木齐市老年慢性病患者对“互联网+健康管理”服务的使用意愿及其影响因素,为优化该服务在健康管理中的应用提供理论依据。方法:于2023年4-7月,采用多阶段分层抽样对1151名乌鲁木齐市60岁以上慢性病患者进行问卷调查,应用lasso回归初步筛选出影响老年慢性病患者使用“互联网+健康管理”服务意愿的因素,采用logistic回归进一步验证老年慢性病患者使用该服务意愿的影响因素。结果:乌鲁木齐市老年慢性病患者“互联网+健康管理”服务使用意愿受性别(OR=0.521)、年龄(OR=0.536)、平均月收入(OR=1.939)、子女经济支持情况(OR=0.673)、知晓“互联网+健康管理”服务情况(OR=0.612)、使用“互联网+健康管理”服务情况(OR=0.403)和使用“互联网+健康管理”服务遇到的困难或顾虑(OR=8.036)等因素的影响,且均有统计学意义(P<0.05)。该服务不同功能模块使用意愿中在线预约挂号功能使用意愿最高(P<0.05)。结论:乌鲁木齐市老年慢性病患者“互联网+健康管理”服务使用意愿受性别、年龄、知晓率、使用情况及子女经济支持等多种因素影响。建议提高该服务知晓率和使用率、优化使用体验以提升意愿,促进健康管理效率。},
	doi = {10.13723/j.yxysh.2025.07.010},
	type = {JOUR}
}

@ARTICLE{ris_000009,
	author = {余新艳 and 马忠 and 曹凡 and 苏鹏 and 林颖 and 张海澄},
	title = {基于单导联可穿戴心电设备预测基层老年心血管代谢疾病患者抑郁发生风险的研究},
	journal = {中国全科医学},
	year = {2026},
	keywords = {抑郁; 心血管代谢疾病; 基层医疗卫生机构; 老年人; 单导联可穿戴心电设备; 列线图; 预测模型 ER -},
	abstract = {背景 心血管代谢疾病与抑郁密切相关。基层心血管代谢疾病管理工作已初具规模,但对于患者抑郁等心理问题一方面缺乏关注,另一方面缺乏简单、准确、高效的筛查评估工具。目的 应用单导联可穿戴心电设备构建宁夏基层老年心血管代谢疾病患者抑郁发生风险的列线图预测模型并验证。方法 选取2022年1月—2023年6月宁夏地区5个市的20家基层医疗卫生机构应用单导联可穿戴心电设备采集并上传至云平台的3 121例65岁以上高血压、糖尿病、冠心病等心血管代谢疾病患者的心电图资料及云平台收集的患者社会人口学、生活行为方式、心理健康等资料。采用简单随机抽样方法按3∶1比例分为训练集(2 341例)和验证集(780例)。通过运行RStudio 4.1.1软件,使用LASSO回归分析以及交叉验证筛选最佳预测因子,采用多因素Logistic回归分析构建预测老年心血管代谢疾病患者抑郁发生风险的列线图预测模型,采用受试者工作特征(ROC)曲线、校正曲线及决策曲线评估模型的效能。结果 LASSO回归筛选出10个变量:性别、BMI、城乡、运动、焦虑、冠心病、期前收缩、RR间期平均值标准差(SDANN)、正常相邻窦性RR间期差值均方根(rMSSD)、睡眠效率;多因素Logistic回归分析结果显示,性别(OR=1.747,95%CI=1.258~2.434)、BMI(OR=1.073,95%CI=1.024~1.125)、城乡(OR=1.684,95%CI=1.172~2.456)、运动(OR=0.610,95%CI=0.460~0.799)、焦虑(OR=3.041,95%CI=1.597~5.484)、冠心病(OR=2.743,95%CI=1.971~3.815),期前收缩(OR=4.745,95%CI=1.681~19.977)、SDANN(OR=4.745,95%CI=1.681~19.977)、rMSSD(OR=0.986,95%CI=0.972~0.999)、睡眠效率(OR=0.988,95%CI=0.982~0.995)是老年心血管代谢疾病患者抑郁发生风险的影响因素(P<0.05)。Logistic回归方程Logit(P)=4.322+0.558×性别+0.071×BMI+0.521×城乡-0.494×运动+1.112×焦虑+1.009×冠心病+1.557×期前收缩-0.011×SDANN-0.014×rMSSD-0.012×睡眠效率,基于此构建列线图预测模型,在训练集和验证集中预测老年慢性病患者抑郁发生风险的ROC曲线下面积分别为0.748(95%CI=0.707~0.786,P<0.001)、0.751(95%CI=0.692~0.809,P<0.001),灵敏度分别为75.2%、76.7%,特异度分别为63.4%、60.6%。临床决策曲线显示,在训练集和验证集中当抑郁风险阈值概率分别在8%~35%、8%~37%时,预测老年心血管代谢疾病患者抑郁发生风险的净收益更高。结论 性别、BMI、城乡、运动、焦虑、冠心病、期前收缩、SDANN、rMSSD、睡眠效率均是老年心血管代谢疾病患者抑郁发生风险的影响因素。本研究基于单导联可穿戴心电设备构建基层老年心血管代谢疾病患者抑郁发生风险的列线图模型,有较好的预测效能及临床应用价值,不但有助于在基层医疗卫生机构对患者进行抑郁筛查与个体化干预措施的制订,还可助力基层心血管疾病防控工作。},
	type = {JOUR}
}

