@ARTICLE{ris_000011,
	author = {施艳鸿 and 颜缘娇 and 林榕 and 黄晨杉 and 李红},
	title = {用户画像在老年慢性病患者健康管理中应用的范围综述},
	journal = {中华护理杂志},
	year = {2025},
	keywords = {用户画像; 慢性病; 老年人; 范围综述; 健康管理; 护理 ER -},
	abstract = {目的 对用户画像在老年慢性病患者健康管理中应用的相关研究进行范围综述,为老年慢性病患者的健康管理提供参考。方法 按照范围综述方法学,系统检索万方数据库、中国知网、维普数据库、中国生物医学文献服务系统、PubMed、Embase、Web of Science、CINAHL、Cochrane Library共9个数据库,检索时限为建库至2024年1月,根据纳入和排除标准筛选文献,由2名研究者独立提取并归纳文献中的信息。结果 共纳入10篇文献。构建用户画像的过程主要包括数据采集、用户特征提取及画像生成与可视化。用户画像在老年慢性病健康管理中应用范围较为广泛,常用于糖尿病、心力衰竭等老年慢性病患者的健康管理,包括制订个性化干预计划、提供个性化健康教育和信息、调整健康管理策略等内容。在老年慢性病患者中应用用户画像,可提升健康信息传递和健康服务的精准度、优化用户使用体验、提高老年慢性病患者自我管理能力和生活质量,优化医疗服务的可及性。结论 用户画像作为一种新兴的健康信息整合手段,可以分析多维度的健康数据,为老年慢性病患者提供个性化、精准的健康管理,改善健康管理效果,降低医疗成本,提高其满意度和参与度,在老年慢性病患者健康管理中具有较好的应用前景。},
	type = {JOUR}
}

@ARTICLE{ris_000012,
	author = {杨丽娟 and 张威 and 李全志 and 郑婷婷 and 杨烁 and 林平 and 韩爽 and 刘思彤 and 张天婧 and 甄健存},
	title = {基于移动技术的居家老年慢病远程药物治疗管理模式建立与评价},
	journal = {医药导报},
	year = {2025},
	keywords = {移动应用; 居家老年慢病患者; 药物治疗管理 ER -},
	abstract = {目的 评价基于移动技术的居家老年慢病远程药物治疗管理模式的效果和可行性。方法 开发便捷友好的移动应用软件(简称“药事宜”APP),组建由三甲医院临床药师-社区药师-社区医师组成的远程药物治疗管理团队,从社区选取居家老年慢病患者进行实践研究,应用“药事宜”APP对患者进行为期6个月的药物治疗管理,考察实践效果和可行性。结果 “药事宜”APP能与多种医疗级可穿戴设备集成连接,实现自动上传监测数据、异常值提醒、用药提醒、用药咨询、用药科普等功能。共有302例居家老年慢病患者完成研究,发现并干预药物治疗问题695例次,药物治疗问题排序前3位的是需要额外增加的治疗247例次(35.5%)、不必要的药物治疗97例次(14.0%)、用药依从性问题93例次(13.4%)。患者用药依从性评分从入组时的(5.85±1.57)分上升至入组6个月后的(6.74±1.23)分(P<0.01),入组6个月后患者对药师工作的满意度评分达(4.99±0.08)分(满分5分),患者平均减少药品费用比例(20.9±18.0)%。93.4%的患者能熟练掌握“药事宜”APP的使用。结论 基于移动技术的居家老年慢病远程药物治疗管理模式能有效提高患者对疾病监测和用药的依从性,保障患者合理用药,减少医疗资源浪费,患者接受度高。},
	type = {JOUR}
}

@ARTICLE{10.19554/j.cnki.1001-3563.2024.20.008,
	author = {夏雅琴 and 廖子璇 and 杨紫懿 and 施晓黎},
