	abstract = {目的 老龄社会,基于移动医疗健康干预平台,依托信息技术,以经济便携的可移动设备为载体,构建面向老年膝骨关节炎患者的自我管理服务系统,提高病患、医生、家属等利益攸关方的信息互联互通,提升病患的自我管理康复和体验。方法 由不同病程的膝骨关节炎患者、家属和专业医师切入,运用服务系统设计理论与方法,围绕患者的生活和康复治疗过程展开系统研究,分析设计需求,构建功能模块。并进一步引入AHP层次分析法对基于需求的功能模块进行权重排序。结果 针对发病率高、治疗周期长、强调离院后自我管理的老年膝骨关节炎,设计完成了一个互联互通、易用高效的“iBONE”膝骨关节炎自我管理系统,依托软件终端与设备终端形成以患者为中心的自我管理康复生态圈。结论 老龄化社会,以服务设计理论与方法赋能居家情境下的移动医疗干预模式,通过智能硬件终端与移动软件终端的系统设计实现慢性病自我康复管理的智能化、居家化、精细化,具有可行性和重要意义。},
	doi = {10.19554/j.cnki.1001-3563.2024.20.008},
	type = {JOUR}
}

