@ARTICLE{ris_000015,
	author = {温方圆 and 杜光会 and 田丰 and 赵小娟},
	title = {患者门户系统在老年冠心病慢病远程管理中的应用及效果},
	journal = {四川大学学报(医学版)},
	year = {2024},
	keywords = {冠心病; 慢病管理; 患者门户系统; 个人电子健康记录; 自护能力; 应对方式; 生活质量 ER -},
	abstract = {目的 探讨基于患者门户系统(PPS)建立的个人电子健康记录(PHR)和慢性病管理平台在老年冠心病患者的应用及对自护能力、应对方式及生活质量的影响。方法 选取2019年1月–2021年6月某三甲医院收治的532例老年冠心病患者为研究对象,随机分为研究组269例和对照组263例。对照组患者进行常规出院办理和随访,研究组患者基于PPS建立的PHR和慢性病管理平台进行出院办理和随访。管理6个月、12个月、18个月后应用自护能力测评表(ESCA)、医学应对问卷(MCMQ)、西雅图心绞痛问卷(SAQ)对两组患者的自护能力、应对方式、生活质量,分析管理效果进行评价。结果 管理前,两组患者的各量表得分差异无统计学意义。管理6个月、12个月、18个月后,两组患者的ESCA量表评分均高于管理前(P<0.05);两组患者MCMQ量表中面对维度评分高于管理前(P<0.05),回避和屈服维度评分低于管理前(P<0.05);两组患者SAQ量表评分均高于管理前(P<0.05)。管理6个月、12个月、18个月后,研究组的ESCA量表评分均高于对照组(P<0.05);研究组的面对维度评分高于对照组,回避和屈服维度评分低于对照组(P<0.05);研究组的SAQ量表评分均高于对照组(P<0.05)。研究组服药依从率为83.27%,高于对照组的69.96%(P<0.05)。研究组不良心血管事件发生率为4.09%,低于对照组的10.27%(P<0.05)。研究组急诊和再入院平均次数低于对照组(P<0.05)。研究组患者满意度评分高于对照组(P<0.05)。结论 基于PPS建立的PHR和慢性病管理平台可提高老年冠心病患者的就医便利性,有利于改善自护能力、应对方式和生活质量,管理效果良好。},
	type = {JOUR}
}

@ARTICLE{ris_000016,
	author = {余新艳 and 苏鹏 and 袁晓静 and 姜清茹 and 杨建云 and 赵旭东 and 王一凡 and 张海澄},
	title = {基层老年慢性病患者心血管疾病综合发生风险的影响因素研究},
	journal = {中国全科医学},
	year = {2024},
	keywords = {慢性病; 基层医疗卫生机构; 老年人; 心血管疾病; 影响因素分析; 变量排序 ER -},
	abstract = {背景 心血管疾病是造成我国居民死亡和疾病负担的首要病因,防控形势严峻。心血管疾病风险影响因素管理是预防心血管疾病的重要基础。但目前国内外应用单导联可穿戴心电设备针对基层老年慢性病患者心血管疾病发生风险的影响因素调查研究较少,且在既往研究中也未以整体观对患者包含不同数量风险的变量重要性进行排序。目的 分析基层管理的65岁以上老年慢性病患者心血管疾病综合发生风险的影响因素,为基层心血管疾病综合防控提供客观依据及帮助。方法 选取2021年12月—2022年9月宁夏回族自治区26家基层医疗卫生机构的3 039例65岁以上+高血压、糖尿病、冠心病其中至少1种慢性病的患者为研究对象。依据72 h心电图分析结果划分为正常组632例、风险组2 407例。分析两组患者基本资料,确定最佳λ值,绘制模型,采用LASSO回归和多因素Logistic回归分析探讨老年慢性病患者心血管疾病综合风险影响因素;并对影响心血管疾病综合风险及包含不同数量风险的变量排序。结果 两组患者年龄、性别、BMI、教育程度、职业、城乡分布、吸烟、运动、冠心病+糖尿病、高血压+冠心病及糖尿病比较,差异均有统计学意义(P<0.05);最佳λ值为0.015 685 31。LASSO回归和多因素Logistic回归模型分析显示年龄、BMI、城乡分布、吸烟、高血压+冠心病+糖尿病是心血管疾病综合风险的影响因素(P<0.05)。受试者工作特征曲线下面积(AUC)=0.650(95%CI=0.627~0.673,P<0.001)。影响综合风险及不同数量风险种类变量排序前五位的分别为:年龄、BMI、城乡分布、饮茶、运动;年龄、高血压+冠心病、性别、城乡分布、吸烟;年龄、高血压+冠心病、性别、BMI、城乡分布;糖尿病+冠心病、年龄、高血压+冠心病、高血压+冠心病+糖尿病、高血压+糖尿病。结论 年龄、BMI、城乡分布、吸烟、高血压合并冠心病及糖尿病是65岁以上+慢性病患者发生心血管疾病风险的影响因素。除年龄外,BMI及生活习惯对心血管疾病综合风险的发生影响较为重要,随着+风险种类数量的增多,慢性病尤其慢性病共病的影响增强。基层医护团队应以单导联可穿戴设备为载体定期对老年慢性病患者进行心血管疾病综合发生风险管理,其不但可高效、低成本的实现心血管疾病发生风险的一级、二级预防及健康管理,并可加速基层医疗服务应加快从不连贯的诊疗服务向全程健康管理的转变。},
	type = {JOUR}
}

