	year = {2024},
	keywords = {技术接受模型; 应用程序; 慢性病; 质性研究 ER -},
	abstract = {目的 了解社区老年慢性病患者智能药盒的使用体验,为进一步增强用户粘性和优化智能药盒提供新思路。方法 采用目的抽样,选取重庆市6所社区的16例老年慢性病患者进行半结构式访谈,应用Colaizzi七步法进行资料分析。结果 社区老年慢性病患者使用智能药盒的体验可归纳为4个主题:“感知有用性”层面的“促进健康”和“肯定智能药盒功能”;“阻碍易用性”层面的“接纳意愿不高”和“技术焦虑”。结论 护理人员应积极突破“信息茧房”,增强内容的科学性,借鉴欧美等国不良事件自我报告工具鼓励患者积极上报,同时提升临床护士保护患者隐私的意识。},
	type = {JOUR}
}

@ARTICLE{10.16405/j.cnki.1004-129x.2023.06.004,
	author = {倪晨旭 and 汤佳 and 邵宝魁 and 王震},
	title = {智能穿戴设备与老年健康——来自智能手环的证据},
	journal = {人口学刊},
	year = {2023},
	keywords = {智能穿戴; 老年健康; 智能手环; 智慧养老 ER -},
	abstract = {老年慢性病是对我国人口健康的重大挑战。传统健康评估体系主要依赖定期机构化检查,操作不便且无法实现持续监测。智能穿戴设备作为一种新兴的健康科技产品,可以提供更为便捷高效的健康监测服务。但是这类设备对健康水平的影响还缺乏充分的实证研究。本文利用全国代表性的大样本老年微观调查数据,通过双向固定效应模型首次评估智能手环对我国老年人健康的影响。结果显示:使用智能手环的老年人在自评健康、抑郁风险、社会适应能力和生活满意度等多个关键健康指标上均有显著改善,采用工具变量法和考察客观健康指标等稳健性检验均证实了因果关系的可靠性。机制分析表明智能手环会通过日常生活风险防范、健康监测筛查慢病、激发积极健康行为和加强社会支持与规范等途径发挥作用。异质性分析发现农村老年人和教育程度较低者可获得更大程度的健康效益,表明智能穿戴设备具有促进健康均等化的潜力。卫生费用分析表明智能手环可通过提高早期诊疗投入产生关键健康收益,并随时间推移遏制医疗费用增长和减轻护理依赖。智能手环展现出即时和持久的医疗经济效益。本文还发现智能手环的健康应用与国家医养结合政策之间存在正向协同效应,为政策提供了微观层面验证支持。本研究为智能手环等新兴智能穿戴设备在提升我国老年人健康水平的效果及机制提供了可靠的实证支撑,为推动智慧养老提供了科学依据。},
	doi = {10.16405/j.cnki.1004-129x.2023.06.004},
	type = {JOUR}
}

@ARTICLE{ris_000019,
	author = {姚琳 and 尚丹梅 and 赵慧 and 刘新宇 and 刘永伟 and 姜涌},
	title = {移动网络在社区老年高血压管理中的效果及满意度调查},
	journal = {中国全科医学},
	year = {2024},
	keywords = {高血压; 慢性病; 社区慢病管理; 老年人; 移动网络; 病人满意度; 治疗结果 ER -},
	abstract = {背景 在信息技术与各行业深度融合和国家大力提倡发展智慧医疗的背景 下,社区慢性病管理也由传统模式逐步向信息化、智慧化管理模式探索和转变。在逐步进入深度老龄化社会的情况下,信息化慢性病管理对老年群体是否有效需要明确。目的 了解移动网络在老年慢性病管理中的作用,并调查其满意度,旨在为开展相关慢性病信息化管理研究提供参考。方法 采用便利抽样法,于2022年1—7月选取锦州市凌河区下辖4个社区650例在社区卫生服务中心登记的高血压老年患者作为研究对象,在知情、自愿前提下,按照居住位置就近优先原则将老年人分为干预组和对照组,每组325例。对照组采用常规社区慢性病管理方式,每两个月面对面随访1次,干预组在对照组的基础上采用移动网络高血压管理方式,干预时长6个月。干预结束后使用高血压知识水平量表(HK-LS)、高血压治疗依从性量表(TASHP)和自我管理行为测评量表(HPSMBRS)进行效果评价,并进行满意度调查。结果 干预后,干预组HK-LS、TASHP和HPSMBRS各维度评分均高于对照组(P<0.05)。93.5%(275/294)的老年人认为移动网络辅助高血压管理方便了就医、86.4%(254/294)的老年人认为能节约就医成本,80.6%(237/294)的老年人认为有助于病情监测;进一步调查影响管理效果的因素主要有身体因素、心理因素、对软硬件设备的不满。结论 移动网络辅助社区高血压管理能有效提升老年患者高血压知识水平、治疗依从性和自我行为管理能力,且满意度较高。},
	type = {JOUR}
}

@ARTICLE{ris_000020,
	author = {余新艳 and 赵珺 and 赵晓晔 and 姜清茹 and 陈雅田 and 王艳 and 张海澄},
	title = {移动智慧医疗在基层老年慢性病患者心血管病防控中的应用研究},
	journal = {中国全科医学},
	year = {2023},
	keywords = {移动医疗; 远程医疗; 单导联可穿戴心电设备; 老年人; 慢性病; 心血管病 ER -},
	abstract = {背景 近年来移动智慧医疗在心血管病的筛查、干预、救治、管理中的优势愈加突出。其中单导联可穿戴心电设备在院外应用于心律失常患者的前期筛查、诊断中的应用价值得到了学者及临床的认可。但因其导联和匹配的云平台功能的单一性,限制了其在基层医疗机构中对慢性非传染疾病(简称慢性病)患者风险筛查及长期随访管理中的应用。目的 本研究立足分级诊疗,从慢性病防控的视角,以单导联可穿戴心电设备为载体,探索移动智慧医疗在基层老年慢病患者中心血管病风险防控中的应用价值。方法 选取2022年1—8月宁夏回族自治区20家基层医疗机构收治的3 000例65岁及以上慢性病患者为研究对象,其中男1 202例、女1 798例;平均年龄(71.3±5.0)岁。基层医生借助手机APP及患者管理云平台录入患者资料,给患者佩戴单导联可穿戴心电设备采集72 h心电数据上传至患者管理云平台。由专业心电图医生分别对数据进行心律失常、心率变异性(HRV)、阻塞性睡眠呼吸暂停综合征(OSAHS)分析及风险分层,并综合3种分析方法的分层结果将心血管病综合风险符合低、中及高危的数据在云平台勾选相应的标识。云平台对高、中危患者以短信形式通知基层医生对患者进行不同流程的管理。统计3种分析方法不同风险分层患者检出例数,低、中、高危心血管病风险患者检出例数及按流程管理率。结果 检出心律失常符合正常、阳性及重大阳性者分别为1 526例(50.87%)、1 349例(44.97%)、125例(4.17%)。2 968例患者完成HRV和OSAHS分析,HRV符合轻度、中度及重度降低者分别为2 330例(78.50%)、630例(21.23%)、8例(0.27%);OSAHS符合轻度、中度、重度异常者分别1 769例(59.60%)、573例(19.31%)、626例(21.09%)。心血管病综合风险为低、中、高危患者分别为744例(24.80%)、1 640例(54.67%)、616例(20.53%)。心血管病综合风险为高、中、低危患者按流程管理率分别为94.49%(703例)、88.10%(1 445例)、100.00%(616例)。结论 将移动智慧医疗技术与心律失常、HRV及OSAHS分析方法联合应用于基层老年慢病患者心血管病防控,心血管病风险检出率和患者管理率较高,有利于基层老年慢性病患者心血管病防控体系的建立。},
	type = {JOUR}
}

@ARTICLE{ris_000021,
	author = {刘晓晨 and 王秀丽 and 马月珍},
	title = {基于“互联网+医联体”的老年慢病患者延续护理实践},
	journal = {护理学杂志},
	year = {2023},
	keywords = {老年患者; 慢性疾病; 医联体; 互联网+; 护理服务; 延续护理; 照顾负担; 职业认同感 ER -},
	abstract = {目的 构建基于“互联网+医联体”的老年慢病患者延续护理模式,并评价实施效果。方法 1所三级医院、1所二级医院、1所社区医院、14家社区卫生服务中心和43家村卫生室建立医联体,对医联体内出院的老年慢病患者,开展“互联网+延续护理”服务。实施前后对患者的满意度、照顾者负担及护士职业认同感进行测评。结果 实施2年7个月,共开展“互联网+医联体”延续护理服务1 859例次,胃管护理最多(37.32%),其次为导尿及相关护理(35.87%);患者对9个条目的满意率为75.59%~100%;实施后,照顾者负担评分显著降低,护士职业认同感得分显著提高(均P<0.05)。结论 基于“互联网+医联体”的老年慢病患者延续护理满足了老年慢病患者的需求,提高患者的满意度,减轻照顾者负担,提升护士职业认同感。},
	type = {JOUR}
}

@ARTICLE{10.16460/j.issn1008-9969.2022.21.074,
	author = {毛佳伊 and 黄欢欢 and 周婷婷 and 谢莉玲 and 陈宇露 and 赵庆华},
	title = {智能药物管理系统在老年慢性病患者住院-居家过渡期的应用},
	journal = {护理学报},
	year = {2022},
	keywords = {慢性病; 老年人; 用药安全; 用药管理; 信息技术 ER -},
	abstract = {目的 研发智能药物管理系统,并探讨该系统在老年慢性病患者住院-居家过渡期中的应用效果。方法 基于协同设计理论,结合前期需求调研,于2021年6-9月,选取某公立医院的老年慢性病住院患者作为研究对象,采用随机数字法进行分组,干预组49例,对照组45例。对照组采用口服药的常规管理模式,干预组采用智能药物管理系统进行用药管理。干预前后调查2组的用药依从性、用药知识和合理用药自我效能得分,干预后收集干预组对系统的评价量表。结果干预组患者的用药依从性、合理用药自我效能得分及均高于对照组(P<0.05);是否使用微信小程序对用药知识得分及差值比较差异无统计学意义(P>0.05);92%的患者对智能药物管理系统具有较高的满意度。结论 智能药物管理系统能有效提高老年慢性病患者的用药依从性及合理用药自我效能,且具有较好的适老性和可行性,拓展了用药安全管理的服务范畴,值得进一步推广。},
	doi = {10.16460/j.issn1008-9969.2022.21.074},
	type = {JOUR}
}

@ARTICLE{ris_000023,
	author = {王雪 and 聂恒卓 and 刘海平},
	title = {OTO模式对社区老年2型糖尿病患者血糖控制水平及自我管理行为能力的影响},
	journal = {中国全科医学},
	year = {2023},
	keywords = {OTO模式; 糖尿病; 2型; 血糖控制; 自我管理行为; 健康管理; 社区卫生服务 ER -},
	abstract = {背景 近年来,信息化管理模式被广泛应用于慢性病患者健康管理。作为国内外常见的“互联网+”慢性病管理模式,整合线上与线下资源的OTO(online-to-offline)模式已由治疗向预防转移,且已被证明可为慢性病管理提供有效支撑。目前国内鲜有OTO模式在老年糖尿病患者中的应用研究。目的 探讨OTO模式对社区老年2型糖尿病患者血糖控制水平及自我管理行为能力的影响。方法 于2020年8—10月,采用便利抽样法,选取从沈阳市某三级甲等医院转介至本市5家社区的老年2型糖尿病患者110例为研究对象,采用随机数字表法按照1∶1的比例将其随机分为对照组(n=55)和干预组(n=55),对其进行为期12个月的干预。对照组给予常规健康管理干预,干预组给予OTO模式健康管理干预。比较两组患者干预前及干预第6个月和12个月的空腹血糖(FBG)、餐后2 h血糖(2 h-PBG)和糖化血红蛋白(HbA1c)水平;比较两组患者干预前后的中文版自我管理行为量表(SDSCA)总得分及各维度得分。结果 最终完成本次研究的患者共105例,其中干预组53例,对照组52例。干预前两组患者FBG、2 h-PBG、HbA1c水平比较,差异无统计学意义(P>0.05)。干预方法和时间对FBG、2 h-PBG、HbA1c水平有交互作用(P<0.05),干预方法和时间在FBG、2 h-PBG、HbA1c水平上主效应显著(P<0.05)。干预组患者干预第6个月和12个月的FBG、2 h-PBG、HbA1c水平均低于干预前,差异有统计学意义(P<0.05);对照组患者干预第6个月和12个月的FBG、2 h-PBG水平低于干预前,差异有统计学意义(P<0.05);干预组患者干预第12个月的FBG、2 h-PBG、HbA1c水平均低于干预第6个月,差异有统计学意义(P<0.05);对照组患者干预第12个月的2 h-PBG水平低于干预第6个月,差异有统计学意义(P<0.05);干预组患者干预第6个月和12个月FBG、2 h-PBG、HbA1c水平均低于对照组同期水平,差异有统计学意义(P<0.05)。干预前,两组患者SDSCA总得分及各维度得分比较,差异无统计学意义(P>0.05);干预后,干预组患者SDSCA总得分及各维度得分高于同组干预前和对照组,差异有统计学意义(P<0.05);干预后,对照组患者SDSCA总得分及各维度得分与干预前相比,差异无统计学意义(P>0.05)。结论 实施OTO模式健康管理有助于老年2型糖尿病患者有效控制血糖水平,提高其自我管理行为能力,有利于实现对糖尿病的长期有效管理。},
	type = {JOUR}
}

@ARTICLE{ris_000024,
	author = {王振苗 and 孙伯玉 and 胡洋洋},
	title = {特殊背景下远程药学干预模式在老年慢性病患者居家用药中的效果},
	journal = {中国老年学杂志},
	year = {2022},
	keywords = {特殊背景; 远程药学干预模式; 慢性病; 居家用药; 用药依从性; 用药安全性; 自我管理能力; 生活质量 ER -},
	abstract = {目的 分析特殊背景下远程药学干预模式在老年慢性病患者居家用药中的应用。方法 90例老年慢性病患者均居家用药,采取随机数字表法分为两组各45例,对照组实施常规用药干预,观察组给予远程药学干预,对比两组干预前后用药依从性、安全用药评分、自我管理能力及生活质量。结果 干预后两组用药依从性差异有统计学意义(P<0.05)。干预后观察组购买药物、认真了解说明书、药效监测、存备药物评分高于对照组,差异有统计学意义(P<0.05)。干预后观察组自我管理量表中健康知识水平、自我概念、自我责任感、自我管理技能及总量表评分高于对照组,差异有统计学意义(P<0.05)。干预后观察组生活质量量表中生理领域、心理领域、社会关系、环境领域及总量表评分高于对照组,差异有统计学意义(P<0.05)。结论 特殊背景下远程药学干预模式在老年慢性病患者居家用药中的应用可明显提高患者的用药依从性及安全性,同时提高患者的自我管理能力及生活质量。},
	type = {JOUR}
}

@ARTICLE{ris_000025,
	author = {熊佳铭 and 余红雨 and 苏瑾 and 赵倬睿 and 杨巧红},
	title = {老年慢性病患者移动医疗照护体验的Meta整合},
	journal = {中华护理杂志},
	year = {2022},
	keywords = {老年人; 慢性病; 移动医疗; 体验; Meta整合; 循证护理学 ER -},
	abstract = {目的 系统评价老年慢性病患者参与移动医疗照护体验的质性研究,为提高和改善老年患者对移动医疗的可及性提供依据。方法 计算机检索PubMed、Embase、The Cochrane Library、Web of Science、Scopus、CINAHL、ProQuest、中国知网、万方数据库、维普中文生物医学期刊、中国生物医学文献数据库,检索有关老年慢性病患者对使用移动医疗的态度和体验的质性研究,检索时限从2000年1月—2022年3月。使用乔安娜布里格斯研究所质性研究评估工具评价文献质量。结果 共纳入22篇研究,提炼出92个明确的研究结果,将相似的研究结果归纳形成12个新类别,综合成3个整合结果:老年慢性病患者参与移动医疗的良好体验、老年慢性病患者参与移动医疗的不佳体验、老年慢性病患者对移动医疗的偏好和期望。结论 老年慢性病患者参与移动医疗的适应体验多样化,需要结合患者情况,从移动医疗设备、医院、社区、家庭和个人多层面完善移动医疗照护服务体系,提升老年慢性病患者使用移动医疗照护服务的可及性和体验。},
	type = {JOUR}
}

