@ARTICLE{10.13286/j.1001-5213.2021.10.16,
	author = {施楠楠 and 甄健存 and 梁健华 and 韩爽 and 杨丽娟 and 武丹威 and 张威 and 宋再伟 and 赵荣生},
	title = {老年高血压患者远程慢病药学服务的实践及效果评价},
	journal = {中国医院药学杂志},
	year = {2021},
	keywords = {慢病管理; 远程药学服务; 高血压; 临床药师 ER -},
	abstract = {目的:探索临床药师主导、基于远程的慢病药学服务实践模式,并对老年高血压患者接受药学服务的效果进行评价。方法:采用前瞻性、随机对照试验设计,纳入符合研究标准的老年高血压出院患者,随机分成两组:干预组和对照组。出院后两组患者分别接受临床药师不同周期及监护级别的随访:干预组前3个月每2周随访1次,后3个月每4周随访1次,由临床药师进行远程用药指导和药学服务;对照组每3个月随访1次,进行一般慢病管理建议。两组随访时间均为6个月。随访方式包括远程药学服务平台、电话及微信,具体选择方式根据患者需求决定。结果:研究共纳入109例符合纳排标准的老年高血压出院患者,有93例患者完成6个月随访,其中干预组48例,对照组45例。出院6个月时,干预组血压达标率显著高于对照组(97.30%vs.63.89%,P<0.05);药物了解程度评分干预组优于对照组[(1.44±0.65)分vs.(2.17±0.66)分,P<0.05];用药依从性评分干预组优于对照组[(1.41±0.69)分vs.(2.17±0.82)分,P<0.05];不良反应的错误处置率显著低于对照组(0.00%vs.61.53%,P<0.05);体质指数(BMI)改善干预组优于对照组(87.80%vs.32.43%,P<0.05)。结论:临床药师主导的远程慢病药学服务可有效改善老年高血压患者血压达标率、对药物的了解程度、用药依从性、不良反应的错误处置率及BMI。},
	doi = {10.13286/j.1001-5213.2021.10.16},
	type = {JOUR}
}
